solution_code:
#include <iostream>
#include <memory>
#include <string>
#include <vector>

int main()
{
    int q{};
    std::cin >> q;

    auto original{ std::make_shared<int>(0) };
    std::vector<std::shared_ptr<int>> extra;

    for (int i{ 0 }; i < q; ++i)
    {
        std::string cmd{};
        std::cin >> cmd;

        if (cmd == "share")
            extra.push_back(original);
        else if (cmd == "release" && !extra.empty())
            extra.pop_back();

        std::cout << original.use_count() << '\n';
    }

    return 0;
}

