solution_code:
#include <iostream>
#include <memory>
#include <vector>

int main()
{
    int value{};
    int r{};
    std::cin >> value >> r;

    auto owner{ std::make_unique<int>(value) };
    std::cout << "exclusive: " << *owner << '\n';

    std::shared_ptr<int> shared{ std::move(owner) };
    std::cout << "published count: " << shared.use_count() << '\n';

    std::vector<std::shared_ptr<int>> readers;
    for (int i{ 0 }; i < r; ++i)
        readers.push_back(shared);
    std::cout << "readers count: " << shared.use_count() << '\n';

    int total{ 0 };
    for (const auto& reader : readers)
        total += *reader;
    std::cout << "total: " << total << '\n';

    readers.clear();
    std::cout << "after readers count: " << shared.use_count() << '\n';

    return 0;
}
